import React, { useRef, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { useTexture } from '@react-three/drei';
import * as THREE from 'three';

function getPhotoPositions(count, radius = 6.5) {
  const positions = [];
  const goldenAngle = Math.PI * (3 - Math.sqrt(5));
  for (let i = 0; i < count; i++) {
    const y = 1 - (i / Math.max(count - 1, 1)) * 2;
    const r = Math.sqrt(1 - y * y);
    const theta = goldenAngle * i;
    const scale = radius * (0.85 + Math.random() * 0.3);
    positions.push([
      Math.cos(theta) * r * scale,
      y * scale * 0.6,
      Math.sin(theta) * r * scale,
    ]);
  }
  return positions;
}

function RealPhotoCard({ url, position, floatOffset, onClick }) {
  const meshRef = useRef();
  const [hovered, setHovered] = useState(false);
  const texture = useTexture(url);

  useFrame((state) => {
    if (!meshRef.current) return;
    meshRef.current.position.y = position[1] + Math.sin(state.clock.elapsedTime * 0.6 + floatOffset) * 0.25;
    meshRef.current.rotation.y += 0.003;
    meshRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.4 + floatOffset) * 0.08;
  });

  return (
    <mesh
      ref={meshRef}
      position={[position[0], position[1], position[2]]}
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}
      scale={hovered ? 1.25 : 1}
    >
      <planeGeometry args={[1.5, 1.1]} />
      <meshStandardMaterial map={texture} side={THREE.FrontSide} />
    </mesh>
  );
}

function ColorCard({ color, position, floatOffset, onClick }) {
  const meshRef = useRef();
  const [hovered, setHovered] = useState(false);
  const threeColor = useMemo(() => new THREE.Color(color), [color]);

  useFrame((state) => {
    if (!meshRef.current) return;
    meshRef.current.position.y = position[1] + Math.sin(state.clock.elapsedTime * 0.6 + floatOffset) * 0.25;
    meshRef.current.rotation.y += 0.003;
    meshRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.4 + floatOffset) * 0.08;
  });

  return (
    <mesh
      ref={meshRef}
      position={[position[0], position[1], position[2]]}
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}
      scale={hovered ? 1.25 : 1}
    >
      <planeGeometry args={[1.5, 1.1]} />
      <meshStandardMaterial color={threeColor} emissive={threeColor} emissiveIntensity={0.5} />
    </mesh>
  );
}

function PhotoCard({ photo, position, floatOffset, onClick }) {
  const isColor = photo.startsWith('__color__');
  if (isColor) {
    return <ColorCard color={photo.replace('__color__', '')} position={position} floatOffset={floatOffset} onClick={onClick} />;
  }
  return <RealPhotoCard url={photo} position={position} floatOffset={floatOffset} onClick={onClick} />;
}

export default function PhotoStars({ photos, onPhotoClick }) {
  const positions = useMemo(() => getPhotoPositions(photos.length), [photos.length]);
  return (
    <group>
      {photos.map((photo, i) => (
        <PhotoCard
          key={i}
          photo={photo}
          position={positions[i]}
          floatOffset={i * 0.7}
          onClick={() => onPhotoClick(photo, i)}
        />
      ))}
    </group>
  );
}
